fun main() {
    val numbers = listOf(1, 2, 3, 4, 5, 6)

    // Use 'it' to represent each individual number
    // We only keep the numbers greater than 3!
    val bigNumbers = numbers.filter { it > 3 }

    println(bigNumbers) // Prints: [4, 5, 6]
}

fun main() {
    val prices = listOf(10, 20, 30)

    // We double every single number concurrently
    val doubled = prices.map { it * 2 }

    println(doubled) // Prints: [20, 40, 60]
}
